import{_ as n,a,b as p}from"./chunks/2025-08-12_194246_5856210.3540283832065939.DJa98GIr.js";import{_ as l,o as t,c as e,ag as i}from"./chunks/framework.DXGyWiRo.js";const r="/media/202508/2025-08-13_174046_7367080.33002152946941854.png",o="/media/202508/2025-08-13_174310_9626070.06315128955528693.png",c="/media/202508/2025-08-13_174431_6906150.07437879899617539.png",u="/media/202508/2025-08-13_174612_1270730.378844024556946.png",v=JSON.parse('{"title":"结构化语义配置","description":"","frontmatter":{"title":"结构化语义配置"},"headers":[],"relativePath":"app-config/structured-semantic.md","filePath":"app-config/structured-semantic.md","lastUpdated":null}'),m={name:"app-config/structured-semantic.md"};function d(_,s,b,g,x,h){return t(),e("div",null,[...s[0]||(s[0]=[i('<p>结构化语义配置概述</p><p>结构化语义配置是传统应用配置技能的地方，支持配置的技能类型有：官方技能、自定义技能、语句问答、关键词问答、设备人设（注意区分这里的设备和极速链路回复角色区别，二者不是一个能力。前者是传统语义技能方式，后者是大模型prompt设置）；并且还支持进行特性设置，如自定义技能或自定义语句问答的阈值设置、关键词过滤、语义敏感词、精简协议。其中包括：</p><h2 id="技能配置" tabindex="-1">技能配置 <a class="header-anchor" href="#技能配置" aria-label="Permalink to &quot;技能配置&quot;">​</a></h2><p>点击“添加”，可在当前应用的情景模式下配置需要的技能。</p><p><img src="'+r+'" alt="" title="null"></p><p><img src="'+o+'" alt="" title="null"></p><h2 id="自定义技能阈值设置" tabindex="-1">自定义技能阈值设置 <a class="header-anchor" href="#自定义技能阈值设置" aria-label="Permalink to &quot;自定义技能阈值设置&quot;">​</a></h2><p>在自定义技能添加界面，勾选自定义技能后，点击技能下的设置图标进行设置，注意支持的技能类型： <strong>自定义私有技能、自定义语句问答</strong> 自定义阈值主要是为了做技能匹配度调节的，可以根据实际需要(模糊匹配度和误识别两个维度)综合考虑设置。 AIUI技能实际触发的模糊匹配程度，可以查看技能json中的source字段取值，可以参考该取值进行自定义技能阈值调整。</p><ul><li>技能阈值越高：技能对出发的语句格式要求越严（模糊匹配越低，不容易误识别）</li><li>技能阈值越低：技能对出发的语句格式要求越送（模糊匹配越高，容易误识别）</li></ul><p><img src="'+n+'" alt="" title="null"></p><p><img src="'+a+`" alt="" title="null"></p><h2 id="技能设置" tabindex="-1">技能设置 <a class="header-anchor" href="#技能设置" aria-label="Permalink to &quot;技能设置&quot;">​</a></h2><p>技能配置后，还可以点击“设置”进行一些高级能力配置，开发者按需设置。</p><ul><li><p><strong>关键词过滤</strong> 过滤识别结果中的关键词，不进行语义理解。常用于过滤唤醒词 比如：唤醒词是“小飞小飞” <strong>过滤前</strong>：“小飞小飞，你好“ <strong>过滤后</strong>：“你好“</p></li><li><p><strong>语义敏感词过滤</strong> 给用户回复的信息中包含敏感信息，可以通过设置过滤掉。支持自定义增加。 注意： 当交互回复触发语义敏感词过滤时，固定响应：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  answer: {</span></span>
<span class="line"><span>      text: &quot;文明社会，请文明用语。&quot;,</span></span>
<span class="line"><span>      topic: &quot;&quot;,</span></span>
<span class="line"><span>      type: &quot;T&quot;</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  operation: &quot;ANSWER&quot;,</span></span>
<span class="line"><span>  rc: 0,</span></span>
<span class="line"><span>  service: &quot;forbidden&quot;,</span></span>
<span class="line"><span>  sid: &quot;xxxxxxxxx&quot;,</span></span>
<span class="line"><span>  state: null,</span></span>
<span class="line"><span>  text: &quot;xxx&quot;,</span></span>
<span class="line"><span>  uuid: &quot;xxxxxxxxx&quot;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div></li><li><p><strong>精简协议</strong> 简化结构化语义，将技能结果分为：媒资类和播报类。默认关闭。 将多个技能精简成一种输出协议，大大降低技能适配工作。适用于无屏设备。</p></li></ul><p><img src="`+c+'" alt="" title="null"></p><p><img src="'+p+'" alt="示例图片"></p><p>注意当AIUI应用不开启<strong>星火大模型配置</strong>时，点击技能设置，还可以配置传统语义链路下的兜底闲聊。开启大模型时，可以由大模型做兜底回复，该能力被替代隐藏。 分别支持的类型有：</p><ul><li>讯飞闲聊</li><li>讯飞视频搜索</li><li>无回复兜底 该能力项下，开发者可以自定义回复语</li></ul><p><img src="'+u+'" alt="" title="null"></p>',19)])])}const k=l(m,[["render",d]]);export{v as __pageData,k as default};
